var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯......"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"나 같은 퇴물에게 이런 중요한 건을 제안하실 줄은 몰랐소.","JPN":"また引退を勧められるのかと思っていたが、まさかこんな重要な提案をしてくれるとはな。","ENG":"I never thought you'd make such a great offer to a has-been like me.","TWN":"沒想到你會對我這種退役的人提出這麼重要的提案。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"이 강화복도 만능은 아니야. 평범한 인간인 이상, 아무리 용을 써 봤자 언젠가 센서도 반응 못할 만큼 빌빌거릴 때가 찾아오겠지.","JPN":"この強化服とて万能ではない。平凡な人間である以上、いかに踏ん張ろうといつかはガタがくる。たとえセンサーの補助があっても無理なものは無理だ。","ENG":"Even this power suit doesn't make me invincible. Since I'm just an ordinary human, I'll eventually grow so weak that its sensors won't respond to me anymore.","TWN":"這件強化服也不是萬能的，只要是凡人，無論再怎麼努力，總有一天也會奄奄一息，連感應器都無法反應了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"하지만......","JPN":"だが……","ENG":"But...","TWN":"但是......"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"늙으면 뻔뻔해진다고, 사장님 말씀을 들으니 욕심이 나는군.","JPN":"人間、歳を取ると図太くなるものらしい。そんな提案をしてもらったら、つい欲が出てしまう。","ENG":"it must be true that you get more shameless as you get older. Your offer makes me want to be selfish.","TWN":"年紀大了臉皮也厚了起來，聽到老闆的話後居然按捺不住了呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"너무 일찍 가 버린 친구들을 위해서라도......","JPN":"先に逝ってしまったかつての戦友たちのためにも……","ENG":"At least for my buddies who left me early,","TWN":"也算是為了那些早逝的朋友們......"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"나는 요양원에 처박히기 전까진 계속 시민들을 지키고 싶소.","JPN":"老人ホーム送りになる寸前まで、私は市民を守り続けていたい。","ENG":"I want to protect citizens until I go to a nursing home.","TWN":"直到被關進老人院之前，我想要一直守護市民。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"그러니 부탁 하나 합시다. 이 퇴물을 좀 도와 주시오.","JPN":"だから、こちらからお願いしたい。このロートルのために手を貸してほしい。","ENG":"So, do me a favor. Help this geezer out.","TWN":"所以我要拜託你一件事，請幫幫我這個老骨頭吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"많은 건 바라지 않소. 그저 현장에 계속 나갈 수만 있으면 됩니다.","JPN":"多くは望まん。ただ、現場に出られるようにしてくれるだけでいい。","ENG":"I don't want many things. I just want to be out in the field for as long as I can.","TWN":"我不奢望太多，只要能繼續前往作戰現場就可以了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};